{"command":"$ErrorActionPreference = 'Stop'
$root = (Get-Location).Path
$tempRoot = Join-Path $root '_codex-stash-backups\github-sync-20260610-1440'
New-Item -ItemType Directory -Force -Path $tempRoot | Out-Null
$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
$results = @()
foreach ($repo in $repos) {
  $repoName = $repo.Name
  $repoPath = $repo.FullName
  $worktreePath = Join-Path $tempRoot $repoName
  $branchName = "codex-sync-$repoName-$(Get-Date -Format yyyyMMddHHmmss)"
  Push-Location $repoPath
  try {
    git fetch origin --prune | Out-Host
    git worktree add -B $branchName $worktreePath origin/sandbox-albert | Out-Host
    Push-Location $worktreePath
    try {
      git merge --no-edit origin/develop | Out-Host
      git push origin HEAD:sandbox-albert | Out-Host
      $head = git rev-parse --short HEAD
      $results += [PSCustomObject]@{Repo=$repoName; RemoteUpdate='ok'; Head=$head; Note='pushed origin/sandbox-albert'}
    } catch {
      git merge --abort 2>$null | Out-Null
      $results += [PSCustomObject]@{Repo=$repoName; RemoteUpdate='failed'; Head=''; Note=$_.Exception.Message}
    } finally {
      Pop-Location
    }
    if (($results | Where-Object { $_.Repo -eq $repoName } | Select-Object -Last 1).RemoteUpdate -eq 'ok') {
      git worktree remove $worktreePath | Out-Host
      git branch -D $branchName | Out-Host
    } else {
      Write-Output "Leaving worktree for inspection: $worktreePath"
    }
  } finally {
    Pop-Location
  }
}
$results | Format-Table -AutoSize","workdir":"C:\repos\dflow plm","timeout_ms":120000}

{"command":"$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
$results = @()
foreach ($repo in $repos) {
  Push-Location $repo.FullName
  Write-Output "[$($repo.Name)]"
  git pull --ff-only --autostash origin sandbox-albert
  $status = git status --short --branch | Select-Object -First 1
  $head = git rev-parse --short HEAD
  $results += [PSCustomObject]@{Repo=$repo.Name; Head=$head; Status=$status}
  Pop-Location
}
$results | Format-Table -AutoSize","workdir":"C:\repos\dflow plm","timeout_ms":120000}

{"command":"$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
foreach ($repo in $repos) {
  Push-Location $repo.FullName
  Write-Output "[$($repo.Name)]"
  git status --short --branch
  git log -1 --oneline
  Pop-Location
}","workdir":"C:\repos\dflow plm","timeout_ms":60000}

