const express = require('express');
const router = express.Router();
const openrouter = require('../helpers/openrouter');
const deepseek = require('../helpers/deepseek');

/**
 * Hardcoded list of models DeepSeek's direct API serves. The shape matches
 * OpenRouter's /models response so the frontend model card renders identically.
 * Pricing is in dollars-per-token (OpenRouter's convention: $0.14/1M → "0.00000014").
 */
const DEEPSEEK_DIRECT_MODELS = {
  data: [
    {
      id: 'deepseek/deepseek-v4-pro',
      name: 'DeepSeek V4 Pro (direct)',
      description: 'Reasoning model with thinking mode. Best HTS classification accuracy. Supports reasoning_effort: high | max.',
      context_length: 128000,
      // prompt = cache-miss input price; prompt_cache = cache-hit input price (~10% of miss)
      pricing: { prompt: '0.00000014', completion: '0.00000028', prompt_cache: '0.000000014' },
    },
    {
      id: 'deepseek/deepseek-v4-flash',
      name: 'DeepSeek V4 Flash (direct)',
      description: 'Faster, cheaper non-reasoning chat model. Does NOT support reasoning_effort.',
      context_length: 64000,
      pricing: { prompt: '0.00000007', completion: '0.00000014', prompt_cache: '0.000000007' },
    },
  ],
};

/**
 * GET /api/openrouter/models?api=openrouter|deepseek-direct
 * Returns the model list for the chosen API. Defaults to OpenRouter.
 */
router.get('/models', async (req, res) => {
  const api = (req.query.api || 'openrouter').toString();
  try {
    if (api === 'deepseek-direct') {
      return res.json(DEEPSEEK_DIRECT_MODELS);
    }
    const data = await openrouter.listUserModels();
    res.json(data);
  } catch (err) {
    const status = err.response?.status ?? 502;
    res.status(status).json({ error: 'Failed to load models', detail: err.message });
  }
});

/**
 * POST /api/openrouter/chat
 * Body: { model, messages, max_tokens?, temperature?, reasoning?, reasoning_effort?, api? }
 *
 * `api` ('openrouter' | 'deepseek-direct'), when provided, forces the routing
 * regardless of the model's prefix. Without it we fall back to auto-detect
 * (deepseek/* models go direct iff DEEPSEEK_API_KEY is set).
 */
router.post('/chat', async (req, res) => {
  const { model, messages, max_tokens, temperature, reasoning, reasoning_effort, api } = req.body || {};
  if (!model || !Array.isArray(messages) || messages.length === 0) {
    return res.status(400).json({ error: 'model and messages are required' });
  }

  const useDeepSeekDirect =
    (api === 'deepseek-direct') ||
    (api == null && model.startsWith('deepseek/') && process.env.DEEPSEEK_API_KEY);

  try {
    let data;
    if (useDeepSeekDirect) {
      if (!process.env.DEEPSEEK_API_KEY) {
        return res.status(400).json({ error: 'DeepSeek Direct selected but DEEPSEEK_API_KEY is not configured' });
      }
      data = await deepseek.chatCompletion({ model, messages, max_tokens, temperature, reasoning_effort });
    } else {
      data = await openrouter.chatCompletion({ model, messages, max_tokens, temperature, reasoning });
    }
    res.json(data);
  } catch (err) {
    const status = err.response?.status ?? 502;
    res.status(status).json({ error: 'Chat completion failed', detail: err.message });
  }
});

module.exports = router;

const jwt = require("jsonwebtoken");
const fs = require("fs");
const publicKey = process.env.JWT_PUBLIC_KEY;
var verifyOptions = {
  algorithm: ["RS256"]
};

function authToken(req, res, next) {
  const token = req.headers.authorization
  if (!token) {
    return false;
  }
  try {
    const decoded = jwt.verify(token, publicKey, verifyOptions);
    req.user = decoded;
  } catch (err) {
    return false;
  }
  return true;
};


function authRole(role) {
  return (req, res, next) => {
    const token = req.headers.authorization
    if (!token) {
      return res.status(403).send("A token is required for authentication");
    }
    return jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
      if (err) {
        return res.status(403).send("Invalid Token");
      } else {
        for (var i = 0; i < role.length; i++) {
          if (decoded.role === role[i] || decoded.role === "admin") {
            return next();
          } 
        }
        return res.status(401).send("You are not authorized to access this resource");
      }
    });
  }
};

async function getUserInfo(token) {
  return new Promise((resolve) => {
    jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
    if (err) {
        resolve(null);
    } else {
        resolve(decoded);
    }
    });
  });
};



module.exports = { authRole, authToken, getUserInfo }


