  chatCompletion: jest.fn(),
}));

jest.mock('../../helpers/auth', () => ({
  authRole: jest.fn((roles) => {
    const middleware = jest.fn();
    middleware.authRoles = roles;
    return middleware;
  }),
}));

describe('openrouter router auth', () => {
  beforeEach(() => {
    mockRoutes.length = 0;
    jest.resetModules();
  });

  test('protects model and chat proxy endpoints with authRole', () => {
    require('../../routes/openrouter.router');

    const models = mockRoutes.find(route => route.method === 'get' && route.path === '/models');
    const chat = mockRoutes.find(route => route.method === 'post' && route.path === '/chat');

    expect(models.handlers[0].authRoles).toEqual(['designer', 'sourcing_manager', 'vendor', 'sales', 'production']);
    expect(chat.handlers[0].authRoles).toEqual(['designer', 'sourcing_manager', 'vendor', 'sales', 'production']);
  });
});

