describe('lead-time router auth', () => {
  beforeEach(() => {
    mockRoutes.length = 0;
    jest.resetModules();
  });

  test('requires login for lead-time reads and calculation', () => {
    require('../../routes/lead-time.router');

    const readRoles = ['admin', 'production', 'sourcing_manager', 'designer', 'sales', 'vendor'];
    const protectedRoutes = [
      ['get', '/design-team-times'],
      ['get', '/licensing-times'],
      ['get', '/factory-times'],
      ['post', '/calculate'],
    ];

    for (const [method, path] of protectedRoutes) {
      const route = mockRoutes.find(entry => entry.method === method && entry.path === path);
      expect(route.handlers[0].authRoles).toEqual(readRoles);
    }
  });

  test('limits lead-time template updates to internal write roles', () => {
    require('../../routes/lead-time.router');

    const writeRoles = ['admin', 'production', 'sourcing_manager', 'designer', 'sales'];
    const updateRoutes = [
      '/design-team-times/:id',
