import { describe, expect, it } from '@jest/globals';
import { Route } from '@angular/router';
import { routes } from './app-routing.module';
import { AuthGuardService as AuthGuard } from './pages/auth/helpers/auth.guard';
import { RoleGuardService as RoleGuard } from './pages/auth/helpers/role-guard.service';

function flattenRoutes(routeList: Route[]): Route[] {
  return routeList.flatMap(route => [
    route,
    ...flattenRoutes((route.children ?? []) as Route[]),
  ]);
}

function findRoute(path: string): Route {
  const route = flattenRoutes(routes as Route[]).find(entry => entry.path === path);
  if (!route) {
    throw new Error(`Route not found: ${path}`);
  }
  return route;
}

describe('admin and role-protected route configuration', () => {
  it('uses RoleGuard for every route that declares role data', () => {
    const roleRoutes = flattenRoutes(routes as Route[]).filter(route => route.data?.['role']);

    for (const route of roleRoutes) {
      expect(route.canActivate).toEqual([RoleGuard]);
      expect(route.canActivate).not.toContain(AuthGuard);
    }
  });

  it('keeps user management admin-only', () => {
    const route = findRoute('apps/admin/users');

    expect(route.canActivate).toEqual([RoleGuard]);
    expect(route.data?.['role']).toEqual(['admin']);
  });

  it('protects direct section routes that used to be login-only', () => {
    const expectedRolesByPath: Record<string, string | string[]> = {
      'apps/itemLibrary': ['admin', 'sales', 'designer', 'production', 'sourcing_manager'],
      'apps/prod-tracking': ['admin', 'production', 'sourcing_manager', 'designer'],
      'apps/licensing-tracking': ['admin', 'production', 'sourcing_manager', 'designer'],
      'apps/lead-time-calculator': ['admin', 'production', 'sourcing_manager', 'designer'],
      'apps/archive': ['admin', 'designer', 'sales', 'production', 'sourcing_manager'],
      'apps/art-piece/:id': ['admin', 'designer', 'sales', 'production'],
    };

    for (const [path, roles] of Object.entries(expectedRolesByPath)) {
      const route = findRoute(path);
      expect(route.canActivate).toEqual([RoleGuard]);
      expect(route.data?.['role']).toEqual(roles);
    }
  });
});

