import { describe, expect, it, jest, beforeEach } from '@jest/globals';
import { RoleGuardService } from './role-guard.service';

function tokenWithRole(role: string): string {
  const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
  const payload = Buffer.from(JSON.stringify({ role, user_id: 42 })).toString('base64url');
  return `${header}.${payload}.signature`;
}

function createGuard(isAuthenticated: boolean) {
  const auth = {
    isAuthenticated: jest.fn().mockResolvedValue(isAuthenticated),
  };
  const router = {
    navigate: jest.fn(),
  };
  const guard = new RoleGuardService(auth as any, router as any, {} as any);
  return { auth, router, guard };
}

describe('RoleGuardService', () => {
  beforeEach(() => {
    localStorage.clear();
  });

  it('allows a user whose token role is in route data', async () => {
    localStorage.setItem('token', tokenWithRole('admin'));
    const { guard, router } = createGuard(true);

    const result = await guard.canActivate({ data: { role: ['admin'] } } as any);

    expect(result).toBe(true);
    expect(router.navigate).not.toHaveBeenCalled();
  });

  it('blocks authenticated users whose role is not allowed', async () => {
    localStorage.setItem('token', tokenWithRole('vendor'));
    const { guard, router } = createGuard(true);

    const result = await guard.canActivate({ data: { role: ['admin'] } } as any);

    expect(result).toBe(false);
    expect(router.navigate).toHaveBeenCalledWith(['pages/error-401']);
  });

  it('redirects unauthenticated users before decoding the token', async () => {
    const { guard, router } = createGuard(false);

    const result = await guard.canActivate({ data: { role: ['admin'] } } as any);

    expect(result).toBe(false);
    expect(router.navigate).toHaveBeenCalledWith(['/login']);
  });

  it('returns an empty role when the token is missing or invalid', () => {
    const { guard } = createGuard(true);

    expect(guard.getRole()).toBe('');

    localStorage.setItem('token', 'not-a-jwt');
    expect(guard.getRole()).toBe('');
  });
});

