Customer.selectedVendor = async (req, result) => {
  req.body = await utility.mapRFQItem(req.body)
  await sql.GridLayout.update(req.body, {
    where: {
      rfqItem_style_number: req.body.rfqItem_style_number
    },
    individualHooks: true
  }).then(data => {
    if (data) {
      result(null, data);
    }
  })
    .catch(err => {
      result(err, null);
    });

}


Customer.generatePriceCode = async (result) => {
  await sql.RFQItem.findAndCountAll().then(data => {
    if (data) {
      let priceCode = {
        RFQItemStatus_id: data.count,
        generatedNumber: Math.floor(Math.random() * 90 + 10)
      }
      result(null, priceCode);
    }
  })
    .catch(err => {
      result(err, null);
    });

}

Customer.addRfqItem = async (req, result) => {
  let remapRFQData = await utility.mapRFQItem(req.body.data)
  if (remapRFQData.rfqItem_copied_from_id) {
    const copyGuard = await rfqCopyMerchGroupGuard.validateRfqCopyPayload(
      sql,
      remapRFQData
    );
    if (!copyGuard.allowed) {
      result(null, {
        status: 403,
        allowed: false,
        message: copyGuard.message,
        reason: copyGuard.reason,
      });
      return;
    }
    const ctx = getContext();
    const user = ctx?.user;
    remapRFQData.rfqItem_copied_on = new Date();
    if (user?.user_id) {
      remapRFQData.rfqItem_copied_by = user.user_id;
    }
  }
  if (!remapRFQData.rfqItem_created_date) {
    remapRFQData.rfqItem_created_date = new Date();
  }
  await sql.RFQItem.create(remapRFQData)
    .then(async (data) => {
      if (data) {
        if (req.body.copyVendors) {
          await sql.RFQVendor.findAll({
            where: {
              RFQitem_id_fk: req.body.data.old_id
            }
          }).then(async (vendors) => {
            if (vendors) {
              const copiedFactoryIds = new Set();
              for (var i = 0; i < vendors.length; i++) {
                await sql.RFQVendor.create({
                  vendor_id_fk: vendors[i].dataValues.vendor_id_fk,
                  RFQVendor_amount: vendors[i].dataValues.RFQVendor_amount,
                  RFQVendor_cbm_pc: vendors[i].dataValues.RFQVendor_cbm_pc,
                  RFQVendor_note: vendors[i].dataValues.RFQVendor_note,
                  RFQVendor_status: null,
                  RFQitem_id_fk: data.dataValues.rfqItem_id,
                  quote_date: vendors[i].dataValues.quote_date
                }).then(() => {
                  // collect factory ids to email after copy
                  if (vendors[i].dataValues.vendor_id_fk) copiedFactoryIds.add(vendors[i].dataValues.vendor_id_fk);
                }).catch(err => {
                });
              }
              // automatically send email notifications to newly added factories
              try {
                const priceCode = remapRFQData?.rfqItem_style_number || req.body?.data?.['Price Code'];
                if (priceCode) {
                  for (const factoryId of copiedFactoryIds) {
                    await emailVendorsForFactory(factoryId, priceCode);
                  }
                }
              } catch (e) {
                console.error('Failed to send vendor emails on copyVendors:', e);
              }
            }
          }).catch(err => {
          })
          result(null, data);
        } else if (req.body.STDImport) {
          let STDItemInfo = await getSelectedSTDItemInfo(req.body.stdSelectedItem)
          let maped_vendor_data = await utility.STDVendorToRFQVendor(STDItemInfo[0], data.dataValues.rfqItem_id);
          data.dataValues.Vendors = [];
          const importedFactoryIds = new Set();
          for (var j = 0; j < maped_vendor_data.length; j++) {
            await sql.RFQVendor.create(maped_vendor_data[j]).then(async (vendor_data) => {
              data.dataValues.Vendors.push(vendor_data.dataValues);
              if (vendor_data?.dataValues?.vendor_id_fk) importedFactoryIds.add(vendor_data.dataValues.vendor_id_fk);
            }).catch((err) => {
            })
          }
          // automatically send email notifications to newly imported factories
          try {
            const priceCode = remapRFQData?.rfqItem_style_number || req.body?.data?.['Price Code'];
            if (priceCode) {
              for (const factoryId of importedFactoryIds) {
                await emailVendorsForFactory(factoryId, priceCode);
              }
            }
          } catch (e) {
            console.error('Failed to send vendor emails on STDImport:', e);
          }
          result(null, data);
        } else {
          result(null, data);
        }
      }
    })
    .catch(err => {
      result(err, null);
    });

}

