async function sendForgotPasswEmail(email, token) {
  const webUrl = getWebUrl(undefined, undefined, { vendorHost: true });
  let url = `"${webUrl}/reset-password/${token}\"`
  let template = buildForgotPasswordEmailTemplate(url);
  const recipients = [email];
  const subject = "Edge Home Forgot Password";
  const messageId = await brevoService.sendEmail(recipients, template, subject);
  if (messageId) {
    await emailService.createEmailLog(recipients, subject, template, messageId);
  }
  return messageId;

}
