'use strict';
/**
 * Regression tests for Customer.updateUser in lib.model.js.
 *
 * Bug fixed: Customer.updateUser was an async function with no try/catch,
 * called from the controller without await.  Any DB error threw an unhandled
 * Promise rejection, which crashes the Node process on Cloud Run → 503.
 *
 * The root-cause that triggered the crash: when editing a factory row in the
 * manage_factories grid view, the frontend sent userType 'Vendor' instead of
 * 'Factory' (because params.node.parent is always truthy for master rows, so
 * the old detection check always branched to the Vendor case).  The backend
 * then queried vendor_id = undefined → SQL error → unhandled rejection → 503.
 *
 * These tests verify:
 * 1. The lib.model.js source wraps the async body in try/catch so that errors
 *    are forwarded to the callback instead of causing unhandled rejections.
 * 2. The factory branch correctly maps factory_country from the request body.
 */

const { readFileSync } = require('fs');
const { join } = require('path');

const LIB_MODEL_PATH = join(__dirname, '../../models/lib.model.js');
const libModelSource = readFileSync(LIB_MODEL_PATH, 'utf8');

// ── source-level guards ───────────────────────────────────────────────────────

describe('Customer.updateUser — source guards', () => {
  it('has a try/catch block inside the async function body', () => {
    // Extract just the updateUser block and confirm it contains try { ... } catch
    const fnIdx = libModelSource.indexOf('Customer.updateUser = async');
    expect(fnIdx).toBeGreaterThan(-1);
    const snippet = libModelSource.slice(fnIdx, fnIdx + 2000);
    expect(snippet).toMatch(/try\s*\{/);
    expect(snippet).toMatch(/catch\s*\(err\)/);
  });

  it('calls result(err, null) inside the catch block to forward errors to the callback', () => {
    const fnIdx = libModelSource.indexOf('Customer.updateUser = async');
    const snippet = libModelSource.slice(fnIdx, fnIdx + 2000);
    const catchIdx = snippet.lastIndexOf('catch');
    const catchBlock = snippet.slice(catchIdx, catchIdx + 100);
    expect(catchBlock).toMatch(/result\(err,\s*null\)/);
  });

  it('maps factory_country from request body in the factory branch', () => {
    const fnIdx = libModelSource.indexOf('Customer.updateUser = async');
    const snippet = libModelSource.slice(fnIdx, fnIdx + 2000);
    expect(snippet).toContain("mapData.factory_country = req['factory_country']");
  });

  it('uses id (not User ID #) as the factory lookup condition', () => {
    const fnIdx = libModelSource.indexOf('Customer.updateUser = async');
    const snippet = libModelSource.slice(fnIdx, fnIdx + 2000);
    // Factory condition must use id, not vendor_id
    expect(snippet).toMatch(/condition\s*=\s*\{id\s*:\s*req\[.id.\]\}/);
  });
});

// ── functional tests with mocked sql ─────────────────────────────────────────

describe('Customer.updateUser — functional (mocked sql)', () => {
  /**
   * We cannot require lib.model.js directly because it in turn requires ./db
   * which tries to connect to PostgreSQL.  Instead, we isolate the updateUser
   * logic by reproducing the narrowest subset needed to test the try/catch
   * contract, matching the actual implementation exactly.
   */

  function makeUpdateUser(sql) {
    return async function updateUser(req, result) {
      try {
        let mapData = {}, condition, db;

        if (req.userType.title.toLowerCase() === 'vendor') {
          mapData.vendor_name      = req['First Name'];
          mapData.vendor_status    = req['Status'];
          mapData.vendor_email     = req['Email'];
          condition = { vendor_id: req['User ID #'] };
          db = 'vendor';
        } else if (req.userType.title.toLowerCase() === 'factory') {
          mapData.factory_name     = req['factory_name'];
          mapData.factory_access   = req['factory_access'];
          mapData.factory_nickname = req['factory_nickname'];
          mapData.factory_status   = req['status'];
          if (req['factory_country'] !== undefined) {
            mapData.factory_country = req['factory_country'];
          }
          condition = { id: req['id'] };
          db = 'Factory';
        } else {
          mapData.name    = req['First Name'];
          mapData.status  = req['Status'];
          mapData.email   = req['Email'];
          mapData.level   = req['Role'];
          condition = { id: req['User ID #'] };
          db = 'users';
        }

        const user = await sql[db].findOne({ where: condition });
        if (user) {
          const data = await user.update(mapData);
          if (data) result(null, { status: true });
          else result(null, { status: false });
        } else {
          result(null, { status: false });
        }
      } catch (err) {
        result(err, null);
      }
    };
  }

  test('factory: calls result(null, {status:true}) on successful update', (done) => {
    const fakeUser = { update: jest.fn().mockResolvedValue(true) };
    const sql = { Factory: { findOne: jest.fn().mockResolvedValue(fakeUser) } };
    const updateUser = makeUpdateUser(sql);

    const req = {
      id: 1,
      factory_name: 'Acme',
      factory_nickname: 'ACM',
      factory_access: 'full',
      status: 'Active',
      factory_country: 'China',
      userType: { title: 'Factory' },
    };

    updateUser(req, (err, data) => {
      expect(err).toBeNull();
      expect(data).toEqual({ status: true });
      expect(sql.Factory.findOne).toHaveBeenCalledWith({ where: { id: 1 } });
      expect(fakeUser.update).toHaveBeenCalledWith(
        expect.objectContaining({ factory_country: 'China' }),
      );
      done();
    });
  });

  test('factory: calls result(null, {status:false}) when factory not found', (done) => {
    const sql = { Factory: { findOne: jest.fn().mockResolvedValue(null) } };
    const updateUser = makeUpdateUser(sql);

    updateUser(
      { id: 999, userType: { title: 'Factory' }, factory_country: 'China' },
      (err, data) => {
        expect(err).toBeNull();
        expect(data).toEqual({ status: false });
        done();
      },
    );
  });

  test('factory: forwards DB errors to the callback instead of throwing (prevents 503)', (done) => {
    const dbError = new Error('connection refused');
    const sql = { Factory: { findOne: jest.fn().mockRejectedValue(dbError) } };
    const updateUser = makeUpdateUser(sql);

    updateUser(
      { id: 1, userType: { title: 'Factory' }, factory_country: 'China' },
      (err, data) => {
        // Must NOT throw an unhandled rejection — error must arrive in callback
        expect(err).toBe(dbError);
        expect(data).toBeNull();
        done();
      },
    );
  });

  test('factory: does not include factory_country in mapData when it is undefined', (done) => {
    const fakeUser = { update: jest.fn().mockResolvedValue(true) };
    const sql = { Factory: { findOne: jest.fn().mockResolvedValue(fakeUser) } };
    const updateUser = makeUpdateUser(sql);

    // factory_country omitted from request (e.g., editing factory_name only)
    updateUser(
      { id: 1, factory_name: 'Acme', userType: { title: 'Factory' } },
      (_err, _data) => {
        const updateCall = fakeUser.update.mock.calls[0][0];
        expect(updateCall).not.toHaveProperty('factory_country');
        done();
      },
    );
  });

  test('vendor: error from vendor table is forwarded to callback (not unhandled)', (done) => {
    const dbError = new Error('vendor query failed');
    const sql = { vendor: { findOne: jest.fn().mockRejectedValue(dbError) } };
    const updateUser = makeUpdateUser(sql);

    updateUser(
      { 'User ID #': 5, 'First Name': 'Jan', userType: { title: 'Vendor' } },
      (err, data) => {
        expect(err).toBe(dbError);
        expect(data).toBeNull();
        done();
      },
    );
  });
});

