const sql = require('../../models/db');
const utility = require('../../helpers/utility');
const Customer = require('../../models/lib.model');

describe('Customer.selectedVendor', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  test('persists the chosen vendor on RFQItem instead of GridLayout', async () => {
    const mappedItem = {
      rfqItem_id: 123,
      rfqItem_style_number: 'RFQ-123',
      rfqItem_choosen_vendor: 77,
      rfqItem_fob_cost: '9.25',
      rfqItem_cbm_per_price: '0.145',
    };
    const rfqItem = { update: jest.fn().mockResolvedValue(mappedItem) };

    utility.mapRFQItem.mockResolvedValue(mappedItem);
    sql.RFQItem.findOne.mockResolvedValue(rfqItem);

    const result = jest.fn();
    await Customer.selectedVendor({ body: { id: 123, 'Chosen Vendor': { id: 77 } } }, result);

    expect(sql.RFQItem.findOne).toHaveBeenCalledWith({ where: { rfqItem_id: 123 } });
    expect(rfqItem.update).toHaveBeenCalledWith(mappedItem);
    expect(sql.GridLayout.update).not.toHaveBeenCalled();
    expect(result).toHaveBeenCalledWith(null, mappedItem);
  });

  test('falls back to price code lookup for legacy callers without an item id', async () => {
    const mappedItem = {
      rfqItem_style_number: 'RFQ-LEGACY',
      rfqItem_choosen_vendor: 88,
    };
    const rfqItem = { update: jest.fn().mockResolvedValue(mappedItem) };

    utility.mapRFQItem.mockResolvedValue(mappedItem);
    sql.RFQItem.findOne.mockResolvedValue(rfqItem);

    await Customer.selectedVendor({ body: { 'Price Code': 'RFQ-LEGACY' } }, jest.fn());

    expect(sql.RFQItem.findOne).toHaveBeenCalledWith({
      where: { rfqItem_style_number: 'RFQ-LEGACY' },
    });
  });
});

