const { describe, test, expect, beforeEach, afterEach } = require('@jest/globals');

describe('ItemLibrary.createItem item number generation', () => {
  let ItemLibrary;
  let sql;
  let utility;
  let getUserInfo;
  let randomSpy;

  beforeEach(() => {
    jest.resetModules();

    sql = {
      itemHeader: {
        findOne: jest.fn(),
        create: jest.fn(),
      },
      RFQItem: {
        findOne: jest.fn(),
      },
      itemAttachment: {
        findOrCreate: jest.fn(),
      },
    };
    utility = {
      mapItemHeader: jest.fn(),
      getItemTypeSearchTerms: jest.fn(() => []),
      scoreItemTypeCandidate: jest.fn(() => 0),
    };
    getUserInfo = jest.fn();

    jest.doMock('../../models/db', () => sql);
    jest.doMock('../../helpers/utility', () => utility);
    jest.doMock('../../helpers/auth', () => ({
      authToken: jest.fn(),
      getUserInfo,
    }));
    jest.doMock('axios', () => jest.fn());

    randomSpy = jest.spyOn(Math, 'random').mockReturnValue(0.42);
    ItemLibrary = require('../../services/item_library.service');
  });

  afterEach(() => {
    randomSpy.mockRestore();
  });

  function baseRequest() {
    return {
      headers: { authorization: 'Bearer token' },
      body: {},
    };
  }

  function mappedItem() {
    return {
      udf_merchgroup01: 'A',
      udf_merchgroup02: 'B',
      udf_merchgroup03: 'C',
      udf_merchgroup04: 'D',
      udf_merchgroup05_fk: 'E',
    };
  }

  test('returns a finite conflict when every generated item number collides', async () => {
    utility.mapItemHeader.mockResolvedValue([mappedItem()]);
    getUserInfo.mockResolvedValue({ name: 'Designer One' });
    sql.itemHeader.findOne.mockResolvedValue({ dataValues: { item_num_id: 'collision' } });
    sql.RFQItem.findOne.mockResolvedValue(null);

    const result = jest.fn();
    await ItemLibrary.createItem(baseRequest(), result);

    expect(sql.itemHeader.findOne).toHaveBeenCalledTimes(25);
    expect(sql.RFQItem.findOne).toHaveBeenCalledTimes(25);
    expect(sql.itemHeader.create).not.toHaveBeenCalled();
    expect(result).toHaveBeenCalledWith(null, {
      statusCode: 409,
      message: 'Unable to generate a unique item number after 25 attempts.',
    });
  });

  test('rebuilds a clean candidate after a collision and saves the unique item number', async () => {
    const item = mappedItem();
    utility.mapItemHeader.mockResolvedValue([item]);
    getUserInfo.mockResolvedValue({ name: 'Designer One' });
    sql.itemHeader.findOne
      .mockResolvedValueOnce({ dataValues: { item_num_id: 'collision' } })
      .mockResolvedValueOnce(null);
    sql.RFQItem.findOne.mockResolvedValue(null);
    sql.itemHeader.create.mockResolvedValue({ dataValues: { item_id_pk: 901 } });

    const result = jest.fn();
    await ItemLibrary.createItem(baseRequest(), result);

    expect(sql.itemHeader.findOne).toHaveBeenCalledTimes(2);
    expect(sql.itemHeader.create).toHaveBeenCalledTimes(1);

    const createdItem = sql.itemHeader.create.mock.calls[0][0];
    expect(createdItem.ref_num).toMatch(/^LIB-ABCD\d-\d{2}-E$/);
    expect(createdItem.ref_num).not.toContain('LIB-ABCDLIB-ABCD');
    expect(result).toHaveBeenCalledWith(null, {
      statusCode: 200,
      data: createdItem.ref_num,
      item_id_pk: 901,
      item_num_id: createdItem.ref_num,
    });
  });
});

